SELECT  FROM tbl_settlement

    deleted = 0

        AND service_type = #{serviceType}


        AND status = #{status}


        AND customer_name LIKE CONCAT('%', #{customerName}, '%')


ORDER BY create_time DESC

SELECT COUNT(1) FROM tbl_settlement

    deleted = 0

        AND service_type = #{serviceType}


        AND status = #{status}


        AND customer_name LIKE CONCAT('%', #{customerName}, '%')

SELECT COALESCE(SUM(total_amount), 0) FROM tbl_settlement
WHERE deleted = 0 AND status >= 2
AND billing_date >= #{monthStart} AND billing_date <= #{monthEnd}
